mapper.select:
SELECT write_year, doc_no, use_yn
  FROM esg.tb_classification_hazards
 WHERE process_id = #{processId}
   AND PROCESS_WORK_REV_NO = #{processWorkRevNo}
   AND WRITE_YEAR = #{writeYear}
   AND use_yn = 'Y'

mapper.insert:

            SELECT LPAD((COALESCE(MAX(DOC_NO::INTEGER), 0) + 1)::TEXT, 5, '0') AS DOC_NO
              FROM esg.tb_classification_hazards
             WHERE WRITE_YEAR = #{writeYear}
			   AND DOC_TYPE = #{docType}

		INSERT INTO esg.tb_classification_hazards (
			 WRITE_YEAR
			,DOC_TYPE
			,DOC_NO
			,COMP_ID
			,PROCESS_ID
			,PROCESS_WORK_REV_NO
			,USE_YN
			,ORDER_SEQ
			,CREATED_AT
			,CREATED_BY
			,WRITE_DT
		) VALUES (
			 #{writeYear}
			,#{docType}
			,#{docNo}
			,#{compId}
			,#{processId}
			,#{processWorkRevNo}
			,#{useYn}
			,#{orderSeq}
			,now()
			,#{createdBy}
			,#{writeDt}
		)

insert.foreach:
        INSERT INTO esg.tb_classification_hazards_detail
        (
			 WRITE_YEAR
			,DOC_TYPE
			,DOC_NO
			,DOC_SEQ
			,HAZARDS_TYPE
			,HAZARDS_CLASSIFICATION
			,CREATED_AT
			,CREATED_BY
		) 
		VALUES 
		( 
			 #{writeYear}
			,#{docType}
			,#{docNo}
			,(SELECT LPAD((COALESCE(MAX(DOC_SEQ::INTEGER), 0) + 1)::TEXT, 5, '0') AS DOC_SEQ
              FROM esg.tb_classification_hazards_detail
             WHERE WRITE_YEAR = #{writeYear})
			,#{list.hazardsType}
			,#{list.hazardsClassification}
			,NOW()
			,#{createdBy}
		);

mapper.delete:

	DELETE FROM ESG.tb_classification_hazards
	WHERE WRITE_YEAR = #{writeYear}
	  AND DOC_TYPE = #{docType}
	  AND DOC_NO = #{docNo};


	DELETE FROM ESG.TB_CLASSIFICATION_HAZARDS_DETAIL
    WHERE WRITE_YEAR = #{writeYear}
	  AND DOC_TYPE = #{docType}
	  AND DOC_NO = #{docNo};

mapper.update:
	UPDATE ESG.tb_classification_hazards 
	   SET PROCESS_ID = #{processId},
	       process_work_rev_no = #{processWorkRevNo},
	       use_yn = #{useYn},
	       order_seq = #{orderSeq},
	       updated_at = now(),
           updated_by = #{updatedBy},
		   write_dt = #{writeDt}
	 WHERE write_year = #{writeYear}
	   AND doc_type = 'CHD'
	   AND doc_no = #{docNo}
	   AND comp_id = #{compId}

		UPDATE ESG.tb_classification_hazards 
		   SET use_yn = 'N',
	           updated_at = now(),
	           updated_by = #{updatedBy}
         WHERE WRITE_YEAR = #{writeYear}
           AND DOC_TYPE = 'CHD'
           AND DOC_NO = #{docNo}
           AND COMP_ID = #{compId}

    	DELETE FROM ESG.TB_CLASSIFICATION_HAZARDS_DETAIL
	     WHERE WRITE_YEAR = #{writeYear}
		   AND DOC_TYPE = #{docType}
		   AND DOC_NO = #{docNo}

mapper.select:
select t1.*
  from esg.tb_classification_hazards_factor_mgmt t1
 where t1.factor_id = #{searchText}
   and t1.comp_id  = #{compId}
 order by t1.use_yn desc, t1.ord_seq asc, t1.created_at asc

mapper.insert:

            select
                case when #{classId} is null or #{classId} = ''
				    then to_char(now(), 'yyyymmdd') || lpad((coalesce(max(substring(class_id from 9 for 4))::int, 0) + 1)::text, 4, '0')
                else #{classId}::varchar
                end as classId
			from esg.tb_classification_hazards_factor_mgmt
			where class_id like to_char(now(), 'YYYYMMDD') || '%'
                and comp_id = #{compId}

		insert into esg.tb_classification_hazards_factor_mgmt (
			comp_id
			, factor_id
			, class_id
			, class_nm
			, use_yn
			, ord_seq
			, created_at
			, created_by
		) values (
			#{compId}
			, #{factorId}
			, #{classId}
			, #{classNm}
			, #{useYn}
			, #{ordSeq}
			, now()
			, #{createdBy}
		)

mapper.update:
update esg.tb_classification_hazards_factor_mgmt set
	class_nm = #{classNm}
	, use_yn = #{useYn}
	, ord_seq = #{ordSeq}
	, updated_at = now()
	, updated_by = #{updatedBy}
where comp_id = #{compId}
	and factor_id = #{factorId}
	and class_id = #{classId}

update esg.tb_classification_hazards_factor_mgmt set
	use_yn = 'N'
	, updated_at = now()
	, updated_by = #{updatedBy}
where comp_id = #{compId}
	and factor_id = #{factorId}
	and class_id = #{classId}
